import type { RentaConfig, RentaLogger } from './types/config.js';
import type { ApiErrorBody } from './errors.js';
import { RentaError, throwApiError } from './errors.js';
import { VERSION } from './version.js';

declare const process: { versions?: { node?: string } } | undefined;

export interface RequestOptions {
  /** JSON-serializable request body. */
  body?: unknown;
  /** URL query parameters. */
  query?: Record<string, string | number | boolean | string[] | undefined>;
  /** Optional idempotency key for write operations. */
  idempotencyKey?: string;
}

export interface ApiResponse<T> {
  /** Parsed response body. */
  data: T;
  /** HTTP status code. */
  status: number;
  /** X-Request-Id from the response. */
  requestId: string;
  /** Parsed rate limit info from response headers. */
  rateLimit: RateLimitInfo;
}

export interface RateLimitInfo {
  limit: number;
  remaining: number;
  reset: number;
}

function getUserAgent(): string {
  if (typeof process !== 'undefined' && process.versions?.node) {
    return `renta-sdk-node/${VERSION} node/${process.versions.node}`;
  }
  if (typeof window !== 'undefined') {
    return `renta-sdk-browser/${VERSION}`;
  }
  return `renta-sdk/${VERSION}`;
}

function buildQueryString(
  params: Record<string, string | number | boolean | string[] | undefined>,
): string {
  const entries: string[] = [];
  for (const [key, value] of Object.entries(params)) {
    if (value === undefined) continue;
    if (Array.isArray(value)) {
      entries.push(
        `${encodeURIComponent(key)}=${value.map(encodeURIComponent).join(',')}`,
      );
    } else {
      entries.push(
        `${encodeURIComponent(key)}=${encodeURIComponent(String(value))}`,
      );
    }
  }
  return entries.length ? `?${entries.join('&')}` : '';
}

function parseRateLimit(headers: Headers): RateLimitInfo {
  return {
    limit: parseInt(headers.get('x-ratelimit-limit') ?? '0', 10),
    remaining: parseInt(headers.get('x-ratelimit-remaining') ?? '0', 10),
    reset: parseInt(headers.get('x-ratelimit-reset') ?? '0', 10),
  };
}

function parseRetryAfter(headers: Headers): number | null {
  const value = headers.get('retry-after');
  if (!value) return null;
  const seconds = parseInt(value, 10);
  if (!isNaN(seconds)) return seconds * 1000; // convert to ms
  const date = Date.parse(value);
  if (!isNaN(date)) return Math.max(0, date - Date.now());
  return null;
}

function jitter(maxMs: number): number {
  return Math.random() * maxMs;
}

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

export class Transport {
  private readonly baseUrl: string;
  private readonly timeout: number;
  private readonly maxRetries: number;
  private readonly retryDelay: number;
  private readonly apiKey: string;
  private readonly _fetch: typeof globalThis.fetch;
  private readonly logger?: RentaLogger;
  private readonly userAgent: string;

  constructor(config: RentaConfig) {
    this.apiKey = config.apiKey;
    this.baseUrl = (config.baseUrl ?? 'https://api.getrenta.io/v1').replace(/\/$/, '');
    this.timeout = config.timeout ?? 30000;
    this.maxRetries = config.maxRetries ?? 3;
    this.retryDelay = config.retryDelay ?? 1000;
    this._fetch = config.fetch ?? globalThis.fetch;
    this.logger = config.logger;
    this.userAgent = getUserAgent();
  }

  async request<T>(
    method: string,
    path: string,
    options?: RequestOptions,
  ): Promise<ApiResponse<T>> {
    const url =
      this.baseUrl + path + (options?.query ? buildQueryString(options.query) : '');

    const headers: Record<string, string> = {
      'Authorization': `Bearer ${this.apiKey}`,
      'User-Agent': this.userAgent,
      'Accept': 'application/json',
    };

    if (options?.body !== undefined) {
      headers['Content-Type'] = 'application/json';
    }

    if (options?.idempotencyKey) {
      headers['Idempotency-Key'] = options.idempotencyKey;
    }

    const bodyStr =
      options?.body !== undefined ? JSON.stringify(options.body) : undefined;

    let lastError: unknown;

    for (let attempt = 0; attempt <= this.maxRetries; attempt++) {
      let response: Response;
      try {
        response = await this._fetch(url, {
          method,
          headers,
          body: bodyStr,
          signal: AbortSignal.timeout(this.timeout),
        });
      } catch (err) {
        if (err instanceof DOMException && err.name === 'TimeoutError') {
          throw new RentaError(
            0,
            { error: { code: 'timeout', message: `Request timed out after ${this.timeout}ms` } },
            '',
          );
        }
        // For AbortError or other fetch errors on Node
        if (err instanceof Error && (err.name === 'TimeoutError' || err.name === 'AbortError')) {
          throw new RentaError(
            0,
            { error: { code: 'timeout', message: `Request timed out after ${this.timeout}ms` } },
            '',
          );
        }
        throw err;
      }

      const requestId = response.headers.get('x-request-id') ?? '';
      const rateLimit = parseRateLimit(response.headers);

      if (response.ok) {
        const data = (await response.json()) as T;
        return { data, status: response.status, requestId, rateLimit };
      }

      // Parse error body
      let errorBody: ApiErrorBody;
      try {
        errorBody = (await response.json()) as ApiErrorBody;
      } catch {
        errorBody = {
          error: {
            code: 'unknown',
            message: `HTTP ${response.status}: ${response.statusText}`,
          },
        };
      }

      const retryAfterMs = parseRetryAfter(response.headers);

      // 429: rate limited — retry
      if (response.status === 429 && attempt < this.maxRetries) {
        const delay =
          retryAfterMs ?? this.retryDelay * Math.pow(2, attempt);
        this.logger?.warn(
          `Rate limited, retrying in ${delay}ms (attempt ${attempt + 1}/${this.maxRetries})`,
          { requestId, status: response.status },
        );
        await sleep(delay + jitter(this.retryDelay * 0.25));
        lastError = { status: response.status, body: errorBody, requestId, retryAfterMs };
        continue;
      }

      // 5xx: server error — retry
      if (response.status >= 500 && attempt < this.maxRetries) {
        const delay = Math.min(
          this.retryDelay * Math.pow(2, attempt) + jitter(this.retryDelay * 0.25),
          30000,
        );
        this.logger?.warn(
          `Server error ${response.status}, retrying in ${Math.round(delay)}ms (attempt ${attempt + 1}/${this.maxRetries})`,
          { requestId, status: response.status },
        );
        await sleep(delay);
        lastError = { status: response.status, body: errorBody, requestId };
        continue;
      }

      // Non-retryable or retries exhausted
      throwApiError(
        response.status,
        errorBody,
        requestId,
        retryAfterMs ? Math.ceil(retryAfterMs / 1000) : undefined,
      );
    }

    // All retries exhausted — throw last error
    if (lastError && typeof lastError === 'object' && 'status' in lastError) {
      const err = lastError as {
        status: number;
        body: ApiErrorBody;
        requestId: string;
        retryAfterMs?: number | null;
      };
      throwApiError(
        err.status,
        err.body,
        err.requestId,
        err.retryAfterMs ? Math.ceil(err.retryAfterMs / 1000) : undefined,
      );
    }

    throw new RentaError(
      0,
      { error: { code: 'unknown', message: 'Request failed after retries' } },
      '',
    );
  }
}
