import type { RentaConfig } from './types/config.js';
import type { PaginatedResponse } from './types/common.js';
import type { ValidateCouponInput, CouponValidation } from './types/coupons.js';
import type { CheckAvailabilityInput, AvailabilityResult, CalculatePricingInput, PricingBreakdown } from './types/common.js';
import type { WaiverTemplateListParams, SignWaiverInput, WaiverSignResult, WaiverTemplate } from './types/waivers.js';
import type {
  ShopProfile,
  StorefrontInventoryParams,
  StorefrontInventoryResult,
  StorefrontBookInput,
  StorefrontBookingResult,
} from './types/storefront.js';
import { Transport } from './transport.js';
import { RentaAuthError } from './errors.js';
import { Paginated, PaginatedPromise } from './pagination.js';

/**
 * Browser-safe Renta client that only accepts publishable keys (renta_pk_).
 * Exposes storefront-specific endpoints for customer-facing UIs.
 */
export class RentaStorefront {
  private readonly transport: Transport;

  constructor(config: RentaConfig) {
    if (!config.apiKey.startsWith('renta_pk_')) {
      throw new RentaAuthError(
        401,
        {
          error: {
            code: 'invalid_key_type',
            message:
              'RentaStorefront requires a publishable key (renta_pk_). Secret keys (renta_sk_) must not be used in client-side code.',
          },
        },
        '',
      );
    }

    this.transport = new Transport(config);
  }

  /** Get the shop profile. */
  async shop(): Promise<ShopProfile> {
    const response = await this.transport.request<ShopProfile>('GET', '/storefront/shop');
    return response.data;
  }

  /** Browse available inventory for given dates. */
  async inventory(params: StorefrontInventoryParams): Promise<StorefrontInventoryResult> {
    const response = await this.transport.request<StorefrontInventoryResult>(
      'GET',
      '/storefront/inventory',
      { query: params as unknown as Record<string, string | number | boolean | undefined> },
    );
    return response.data;
  }

  /** Create a storefront booking (requires confirmed payment). */
  async book(input: StorefrontBookInput): Promise<StorefrontBookingResult> {
    const response = await this.transport.request<StorefrontBookingResult>(
      'POST',
      '/storefront/book',
      { body: input },
    );
    return response.data;
  }

  /** Validate a coupon code. */
  async validateCoupon(input: ValidateCouponInput): Promise<CouponValidation> {
    const response = await this.transport.request<CouponValidation>(
      'POST',
      '/coupons/validate',
      { body: input },
    );
    return response.data;
  }

  /** Calculate pricing for items + dates. */
  async calculatePricing(input: CalculatePricingInput): Promise<PricingBreakdown> {
    const response = await this.transport.request<PricingBreakdown>(
      'POST',
      '/pricing/calculate',
      { body: input },
    );
    return response.data;
  }

  /** Check availability for items + dates. */
  async checkAvailability(input: CheckAvailabilityInput): Promise<AvailabilityResult> {
    const response = await this.transport.request<AvailabilityResult>(
      'POST',
      '/availability/check',
      { body: input },
    );
    return response.data;
  }

  /** List waiver templates. */
  waiverTemplates(params?: WaiverTemplateListParams): PaginatedPromise<WaiverTemplate> {
    const initialPromise = this.transport
      .request<PaginatedResponse<WaiverTemplate>>('GET', '/waivers/templates', {
        query: params as unknown as Record<string, string | number | boolean | undefined>,
      })
      .then((r) => r.data);

    const fetchPage = (cursor: string) =>
      this.transport
        .request<PaginatedResponse<WaiverTemplate>>('GET', '/waivers/templates', {
          query: { ...params, cursor } as unknown as Record<string, string | number | boolean | undefined>,
        })
        .then((r) => r.data);

    return Paginated.from(initialPromise, fetchPage);
  }

  /** Sign a waiver. */
  async signWaiver(input: SignWaiverInput): Promise<WaiverSignResult> {
    const response = await this.transport.request<WaiverSignResult>(
      'POST',
      '/waivers/sign',
      { body: input },
    );
    return response.data;
  }
}
